            $output .= "<span id='$kblink_id'>";
            $output .= '&nbsp;'.$item->getLinks();
            $output .= "</span>";
            $paramscomment['withlink'] = $kblink_id;
            $output .= Ajax::updateItemOnSelectEvent($field_id, $kblink_id,
